// submit.js

export const SubmitButton = () => {
  return (
    <div
      style={{
        display: 'flex',
        alignItems: 'center',
        justifyContent: 'center',
        marginTop: '20px',
      }}
    >
      <button
        type="submit"
        style={{
          background: "#2563eb",
          color: "white",
          border: "none",
          borderRadius: "8px",
          padding: "10px 18px",
          cursor: "pointer",
          fontWeight: 600,
          fontSize: "14px",
        }}
      >
        Submit
      </button>
    </div>
  );
};
